-- ============================================\n-- 义齿工厂面试预约系统 - 应聘信息表创建脚本\n-- 请在 Supabase SQL Editor 中执行此脚本\n-- ============================================\n\n-- 创建应聘信息表\nCREATE TABLE IF NOT EXISTS applications (\n  id SERIAL PRIMARY KEY,\n  name VARCHAR(100) NOT NULL,\n  gender VARCHAR(10) NOT NULL,\n  phone VARCHAR(20) NOT NULL,\n  age INT NOT NULL,\n  position VARCHAR(100) NOT NULL,\n  education VARCHAR(50) NOT NULL,\n  experience VARCHAR(50) NOT NULL,\n  skills TEXT,\n  work_experience TEXT,\n  salary_expectation VARCHAR(100),\n  notes TEXT,\n  status VARCHAR(20) DEFAULT 'pending',\n  created_at TIMESTAMP DEFAULT NOW(),\n  updated_at TIMESTAMP DEFAULT NOW()\n);\n\n-- 创建索引以提高查询性能\nCREATE INDEX IF NOT EXISTS idx_applications_phone ON applications(phone);\nCREATE INDEX IF NOT EXISTS idx_applications_position ON applications(position);\nCREATE INDEX IF NOT EXISTS idx_applications_status ON applications(status);\nCREATE INDEX IF NOT EXISTS idx_applications_created_at ON applications(created_at);\n\n-- 设置行级安全策略\nALTER TABLE applications ENABLE ROW LEVEL SECURITY;\n\n-- 允许匿名读取和插入\nCREATE POLICY "Allow anonymous select on applications" ON applications\n  FOR SELECT TO anon USING (true);\n\nCREATE POLICY "Allow anonymous insert on applications" ON applications\n  FOR INSERT TO anon WITH CHECK (true);\n\nCREATE POLICY "Allow anonymous update on applications" ON applications\n  FOR UPDATE TO anon USING (true) WITH CHECK (true);\n\n-- 完成\nSELECT '应聘信息表创建成功！' as message;